DO $$
DECLARE
  d   jsonb := $jdata$[{"slug":"dji-agras-t50","name":"DJI Agras T50","manufacturer":"DJI","type":"drone","introduced_year":2023,"specs_json":{"weight_kg":47.5,"payload_kg":50,"tank_capacity_l":40,"spray_width_m":9,"max_speed_ms":10,"battery":"TB50 intelligent flight battery","ip_rating":"IP67","drive":"octorotor coaxial","radar":"true","rtk":"true"},"failure_modes":[{"component":"spray nozzle \u2014 clogging and abrasion wear","symptom":"spray flow rate drops > 15% below setpoint; uneven swath distribution visible in coverage map; nozzle output pressure alarm","root_cause":"agricultural chemical residue crystallisation inside flat-fan nozzle orifice during drying between missions; abrasive pesticide particulates erode orifice geometry causing atomization degradation","severity":"high","mtbf_hours":80,"source_urls":["unverified-training-data"],"confidence":"low","tags":["spray-system","nozzle","clogging","wear","agricultural"],"repair_protocol":{"title":"Spray Nozzle Cleaning and Replacement","steps":[{"step":1,"action":"Power off aircraft; release spray system pressure by opening nozzle caps","tool":null,"warning":"Never point nozzle at face or unprotected skin \u2014 residual chemical pressure"},{"step":2,"action":"Remove nozzle bodies (quarter-turn unlock); soak in clean water for 10 minutes","tool":"nozzle removal tool (DJI-NR1)"},{"step":3,"action":"Use nozzle cleaning brush to clear orifice; backflush with clean water via nozzle cleaning port","tool":"nozzle cleaning brush set, syringe with clean water"},{"step":4,"action":"Inspect orifice diameter with nozzle gauge \u2014 replace if orifice worn > 5% of nominal diameter","tool":"nozzle gauge set"},{"step":5,"action":"Install new nozzle if worn; quarter-turn lock; verify click-lock engagement","tool":"nozzle removal tool"},{"step":6,"action":"Run spray system test via DJI Agras app \u2014 flow rate must be within 5% of target at operating pressure","tool":"DJI Agras mobile app, flow rate indicator"}],"tools_required":["DJI nozzle removal tool NR1","nozzle cleaning brush set","syringe","nozzle gauge set","DJI Agras mobile app"],"parts":[{"part_name":"DJI Agras T50 Flat-Fan Nozzle Set (8x)","part_number":"CP.AG.00000455.01","supplier":"DJI Official Store","unit_cost_usd":48,"qty":1}],"labor_minutes":20,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"spray_flow_rate_deviation_pct","signal_source":"flow sensor telemetry","threshold_value":10,"threshold_operator":">","threshold_unit":"percent from setpoint","lead_time_hours":2,"confidence":0.85},{"signal_name":"nozzle_operating_hours","signal_source":"mission log","threshold_value":60,"threshold_operator":">","threshold_unit":"hours","lead_time_hours":8,"confidence":0.8}]},{"component":"centrifugal pump seal \u2014 wear and chemical degradation","symptom":"spray system pressure drops below 0.3 MPa; pump motor current rises 20%+ above baseline; chemical leak visible at pump body","root_cause":"pump mechanical seal faces erode from abrasive agricultural chemical suspensions; seal material (PTFE or carbon-graphite) requires replacement every 200 operating hours; some pH extremes in fertiliser mixes accelerate degradation","severity":"high","mtbf_hours":200,"source_urls":["unverified-training-data"],"confidence":"low","tags":["spray-system","pump","seal","chemical","wear"],"repair_protocol":{"title":"Centrifugal Pump Mechanical Seal Replacement","steps":[{"step":1,"action":"Power off; drain tank and spray lines completely; wear chemical-resistant gloves throughout","tool":"gloves, drain bucket","warning":"Assume all wetted surfaces are contaminated with agricultural chemical \u2014 PPE required"},{"step":2,"action":"Remove pump from airframe (4x M5 bolts); collect any residual fluid","tool":"4mm hex wrench"},{"step":3,"action":"Disassemble pump housing (6x M4 screws); expose impeller and seal faces","tool":"3mm hex wrench"},{"step":4,"action":"Remove impeller retaining nut; extract impeller; remove worn seal from shaft","tool":"impeller removal tool, circlip pliers"},{"step":5,"action":"Clean shaft and housing bore with clean water; inspect for shaft scoring","tool":"lint-free cloth, water"},{"step":6,"action":"Install new mechanical seal (PTFE-faced); press rotating seat onto shaft to full contact; install stationary seat in housing","tool":"seal installation tool, clean gloves"},{"step":7,"action":"Reinstall impeller; torque nut to 8 Nm; reassemble pump housing; reinstall to airframe","tool":"torque wrench 0-20 Nm, 4mm hex wrench"},{"step":8,"action":"Fill tank with clean water; run pump for 3 minutes; inspect for leaks; verify pressure > 0.35 MPa at nominal flow","tool":"DJI Agras app, pressure gauge"}],"tools_required":["4mm hex wrench","3mm hex wrench","circlip pliers","torque wrench 0-20 Nm","impeller removal tool","PPE chemical-resistant gloves","DJI Agras app"],"parts":[{"part_name":"DJI Agras T50 Pump Mechanical Seal Kit","part_number":"CP.AG.00000438.01","supplier":"DJI Official Store","unit_cost_usd":35,"qty":1}],"labor_minutes":60,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"pump_pressure_mpa","signal_source":"spray system pressure sensor","threshold_value":0.32,"threshold_operator":"<","threshold_unit":"MPa","lead_time_hours":4,"confidence":0.8},{"signal_name":"pump_motor_current_a","signal_source":"ESC telemetry","threshold_value":12,"threshold_operator":">","threshold_unit":"amperes","lead_time_hours":8,"confidence":0.72}]},{"component":"ESC thermal shutdown \u2014 motor overtemperature","symptom":"mid-mission ESC over-temperature fault; aircraft reduces speed and altitude; asymmetric motor throttle output; ESC LED flashes red","root_cause":"coaxial octorotor ESC operates at sustained high duty cycle during heavy-payload spray missions; thermal interface between ESC PCB and arm tube degrades from vibration-induced fretting; ESC junction temperature exceeds 95C trip threshold","severity":"high","mtbf_hours":500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["ESC","thermal","electrical","motor","payload"],"repair_protocol":{"title":"ESC Thermal Interface Refresh and Inspection","steps":[{"step":1,"action":"Power off; remove ESC access cover from arm (2x M3 screws)","tool":"JIS #1 screwdriver"},{"step":2,"action":"Remove ESC from arm tube (4x M3 mounting screws); inspect thermal pad between ESC and arm","tool":"JIS #1 screwdriver"},{"step":3,"action":"Remove degraded thermal pad; clean ESC back and arm contact surface with IPA","tool":"IPA, lint-free cloth, plastic scraper"},{"step":4,"action":"Install new 1mm thermal pad (Fujipoly XR-m or equivalent 6 W/mK); press ESC firmly to arm surface; reinstall mounting screws","tool":"torque wrench 0-2 Nm"},{"step":5,"action":"Inspect ESC for capacitor bulging or PCB burn marks; if present, replace ESC module","tool":"magnifying glass, inspection light"},{"step":6,"action":"Power on; run DJI Agras diagnostic; verify ESC idle temp < 45C at ambient 25C; perform test flight at 80% payload","tool":"DJI Agras app"}],"tools_required":["JIS #1 screwdriver","torque wrench 0-2 Nm","IPA","lint-free cloth","magnifying glass","DJI Agras app"],"parts":[{"part_name":"Fujipoly XR-m Thermal Gap Pad 50x50x1mm","part_number":"FUJIPOLY-XRM-50X1","supplier":"Fujipoly / Digi-Key","unit_cost_usd":18,"qty":8},{"part_name":"DJI Agras T50 ESC Module","part_number":"CP.AG.00000412.01","supplier":"DJI Official Store","unit_cost_usd":280,"qty":1}],"labor_minutes":45,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"esc_temp_max_c","signal_source":"ESC telemetry via DJI link","threshold_value":88,"threshold_operator":">","threshold_unit":"celsius","lead_time_hours":2,"confidence":0.82},{"signal_name":"esc_throttle_asymmetry_pct","signal_source":"flight controller telemetry","threshold_value":10,"threshold_operator":">","threshold_unit":"percent","lead_time_hours":4,"confidence":0.7}]},{"component":"propeller \u2014 blade delamination from chemical exposure","symptom":"vibration level increases 30%+ above baseline during flight; single propeller RPM drops vs commanded; visual delamination or blistering on prop surface","root_cause":"agricultural chemicals (herbicides, fungicides) in aerosol overspray contact propeller blade surface; some chemical combinations attack propeller composite matrix resin causing surface delamination; UV exposure accelerates matrix degradation","severity":"critical","mtbf_hours":300,"source_urls":["unverified-training-data"],"confidence":"low","tags":["propeller","delamination","chemical","structural","safety"],"repair_protocol":{"title":"Propeller Chemical Damage Inspection and Replacement","steps":[{"step":1,"action":"Pre-flight: inspect all propeller blades under good lighting for surface blistering, delamination, or discoloration; run fingertip across blade surface \u2014 any roughness or bubbles = replace","tool":"flashlight"},{"step":2,"action":"Remove suspect propeller: loosen motor prop lock (counter-clockwise on CW-rotation motors, clockwise on CCW-rotation motors)","tool":"DJI prop installation/removal wrench"},{"step":3,"action":"Inspect motor shaft for chemical corrosion; clean with IPA if surface oxidation present","tool":"IPA, lint-free cloth"},{"step":4,"action":"Install new propeller; tighten prop lock to click; verify it cannot be pulled off by hand","tool":"DJI prop wrench","warning":"Never reuse delaminating propellers \u2014 blade separation during flight will cause crash under heavy payload"},{"step":5,"action":"Post replacement: run motor run-up test via DJI Agras app; verify vibration < 1.5g RMS on IMU","tool":"DJI Agras app, vibration monitoring"}],"tools_required":["DJI prop installation/removal wrench","IPA","DJI Agras app"],"parts":[{"part_name":"DJI Agras T50 Propeller (2x CW + 2x CCW)","part_number":"CP.AG.00000441.01","supplier":"DJI Official Store","unit_cost_usd":85,"qty":2}],"labor_minutes":15,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"imu_vibration_rms_g","signal_source":"flight controller IMU","threshold_value":1.8,"threshold_operator":">","threshold_unit":"g RMS","lead_time_hours":1,"confidence":0.88},{"signal_name":"propeller_hours_since_last_inspection","signal_source":"maintenance log","threshold_value":40,"threshold_operator":">","threshold_unit":"hours","lead_time_hours":8,"confidence":0.82}]},{"component":"TB50 intelligent battery \u2014 cell imbalance from agricultural heat","symptom":"battery remaining capacity shows > 15% drop from last full charge; pre-flight check aborts with battery health warning; battery surface temperature > 50C after charge","root_cause":"TB50 batteries stored in direct sun on aircraft between spray passes experience ambient temperatures 50-70C in agricultural settings; accelerated cell degradation from sustained heat during operation; cell group imbalance develops faster than BMS can compensate","severity":"high","mtbf_hours":600,"source_urls":["unverified-training-data"],"confidence":"low","tags":["battery","thermal","BMS","agricultural","storage"],"repair_protocol":{"title":"TB50 Battery Health Assessment and Replacement","steps":[{"step":1,"action":"Check battery health via DJI Agras app \u2014 navigate to Battery > Battery Details; record cycle count and remaining capacity percentage","tool":"DJI Agras app"},{"step":2,"action":"If remaining capacity < 80% of rated or cycle count > 200: retire battery","tool":null},{"step":3,"action":"Allow battery to cool to < 40C before charging \u2014 never charge hot battery; store in shade","tool":"IR thermometer"},{"step":4,"action":"Perform 3 full charge-discharge cycles using DJI battery station to recalibrate BMS capacity estimate","tool":"DJI Agras battery charging station"},{"step":5,"action":"If capacity recovers to > 85% after reconditioning, return to service; otherwise replace","tool":"DJI Agras app"},{"step":6,"action":"Dispose via DJI battery return program; do not puncture or landfill LiPo batteries","tool":null}],"tools_required":["DJI Agras app","IR thermometer","DJI Agras battery charging station"],"parts":[{"part_name":"DJI Agras T50 TB50 Intelligent Flight Battery","part_number":"CP.AG.00000397.01","supplier":"DJI Official Store","unit_cost_usd":480,"qty":1}],"labor_minutes":10,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"battery_remaining_capacity_pct","signal_source":"DJI BMS via link telemetry","threshold_value":82,"threshold_operator":"<","threshold_unit":"percent of rated","lead_time_hours":24,"confidence":0.85},{"signal_name":"battery_cycle_count","signal_source":"DJI BMS","threshold_value":180,"threshold_operator":">","threshold_unit":"cycles","lead_time_hours":48,"confidence":0.8}]},{"component":"phased array radar \u2014 radome contamination","symptom":"obstacle avoidance false positives in clean airspace; radar range reduced from 50m to 20m; field map shows phantom obstacles","root_cause":"DJI T50 phased array radar uses 77GHz millimeter wave; agricultural chemical residue builds up on radome surface creating dielectric layer that attenuates and reflects radar signal; wet chemical film worse than dry","severity":"medium","mtbf_hours":50,"source_urls":["unverified-training-data"],"confidence":"low","tags":["radar","sensor","contamination","obstacle-avoidance"],"repair_protocol":{"title":"Radar Radome Chemical Residue Cleaning","steps":[{"step":1,"action":"Power off aircraft; inspect radar radome (lower and forward facing) for chemical film or residue deposits","tool":"flashlight, oblique viewing angle"},{"step":2,"action":"Dampen microfiber cloth with clean water; gently wipe radome in straight strokes; avoid circular motion","tool":"microfiber cloth, clean water"},{"step":3,"action":"If residue persists, use DJI-approved radome cleaner solution (mild pH 7 aqueous); do not use solvents","tool":"pH-neutral cleaner, microfiber cloth","warning":"Never use acetone, IPA, or agricultural chemical cleaners on radar radome \u2014 will etch the radome coating"},{"step":4,"action":"Dry with clean microfiber; power on; run radar self-test via DJI Agras app; verify obstacle detection range > 40m in open field","tool":"DJI Agras app, measuring tape"}],"tools_required":["microfiber cloth","clean water","pH-neutral cleaner","DJI Agras app","measuring tape"],"parts":[],"labor_minutes":10,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"radar_max_detection_range_m","signal_source":"DJI radar diagnostics","threshold_value":30,"threshold_operator":"<","threshold_unit":"meters","lead_time_hours":2,"confidence":0.78},{"signal_name":"radar_false_positive_rate_per_min","signal_source":"obstacle avoidance log","threshold_value":3,"threshold_operator":">","threshold_unit":"false detections per minute","lead_time_hours":1,"confidence":0.72}]},{"component":"motor bearing \u2014 dusty/wet agricultural environment wear","symptom":"motor vibration signature changes; individual motor current deviates > 15% from fleet average; motor temperature 10C above peers at same throttle","root_cause":"agricultural dust and chemical mist bypass motor can seals over time; bearing contamination accelerates race wear; DJI T50 operates in intensely dusty environments during dry-field applications","severity":"high","mtbf_hours":400,"source_urls":["unverified-training-data"],"confidence":"low","tags":["motor","bearing","dust","wear","contamination"],"repair_protocol":{"title":"Motor Bearing Inspection and Replacement","steps":[{"step":1,"action":"Power off; identify suspect motor by telemetry; remove propeller","tool":"DJI prop wrench"},{"step":2,"action":"Spin motor shaft by hand \u2014 feel for roughness, binding, or grinding; any detected: replace motor","tool":null},{"step":3,"action":"Remove motor from arm (4x M3 mounting screws)","tool":"JIS #1 screwdriver"},{"step":4,"action":"Field-level replacement: install new DJI T50 motor; torque M3 screws to 1.5 Nm in star pattern","tool":"JIS #1 screwdriver, torque wrench 0-3 Nm"},{"step":5,"action":"Reinstall propeller; run motor run-up test; verify vibration < 1.2g RMS","tool":"DJI Agras app"}],"tools_required":["DJI prop wrench","JIS #1 screwdriver","torque wrench 0-3 Nm","DJI Agras app"],"parts":[{"part_name":"DJI Agras T50 Motor Assembly","part_number":"CP.AG.00000418.01","supplier":"DJI Official Store","unit_cost_usd":165,"qty":1}],"labor_minutes":20,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"motor_current_deviation_pct","signal_source":"ESC telemetry","threshold_value":12,"threshold_operator":">","threshold_unit":"percent from fleet average","lead_time_hours":8,"confidence":0.78},{"signal_name":"motor_temp_delta_c","signal_source":"motor temperature sensor","threshold_value":12,"threshold_operator":">","threshold_unit":"celsius above fleet average","lead_time_hours":4,"confidence":0.75}]},{"component":"flow rate sensor \u2014 chemical scale buildup","symptom":"flow rate reading drifts > 10% from actual flow; autopilot spray rate varies across field; coverage map shows inconsistent application bands","root_cause":"ultrasonic flow sensor exposed to full chemical flow path; dissolved mineral salts and chemical residue crystallise on sensor face and tubing walls; deposits alter acoustic path and reduce measurement accuracy","severity":"medium","mtbf_hours":150,"source_urls":["unverified-training-data"],"confidence":"low","tags":["spray-system","sensor","flow","scale","calibration"],"repair_protocol":{"title":"Flow Rate Sensor Descaling and Calibration","steps":[{"step":1,"action":"Drain spray system; connect clean water to inlet; flush 5 litres through nozzles","tool":"clean water source, bucket"},{"step":2,"action":"Prepare citric acid solution 5% by weight in water; fill tank with 5 litres of solution","tool":"citric acid powder, 5L water, measuring scale"},{"step":3,"action":"Run spray pump for 5 minutes; allow solution to soak in lines for 20 minutes; drain and flush with 10 litres clean water","tool":"DJI Agras app (manual spray mode), bucket"},{"step":4,"action":"Run flow sensor calibration via DJI Agras app: Maintenance > Spray System > Flow Calibration","tool":"DJI Agras app, known-volume collection vessel"},{"step":5,"action":"If calibration error > 10% persists after descaling, replace flow sensor module","tool":null}],"tools_required":["DJI Agras app","citric acid powder","measuring scale","collection vessel 5L","clean water source"],"parts":[{"part_name":"DJI Agras T50 Flow Sensor Module","part_number":"CP.AG.00000451.01","supplier":"DJI Official Store","unit_cost_usd":95,"qty":1}],"labor_minutes":40,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"flow_rate_vs_setpoint_deviation_pct","signal_source":"spray system controller","threshold_value":8,"threshold_operator":">","threshold_unit":"percent","lead_time_hours":4,"confidence":0.8}]}],"suppliers":[{"name":"DJI Official Store","website":"https://store.dji.com","region":"CN","component_types":["nozzle","pump seal","propeller","battery","ESC","motor","flow sensor"],"lead_time_days":7,"risk_level":"low"}],"research_sources":["unverified-training-data"]},{"slug":"dji-agras-t60","name":"DJI Agras T60","manufacturer":"DJI","type":"drone","introduced_year":2024,"specs_json":{"weight_kg":55.5,"payload_kg":60,"tank_capacity_l":50,"spray_width_m":11,"max_speed_ms":12,"battery":"TB60 intelligent flight battery","ip_rating":"IP67","drive":"octorotor coaxial","dual_pump":true,"radar":"true","rtk":"true"},"failure_modes":[{"component":"dual pump solenoid valve \u2014 sticky valve from crystallised chemical","symptom":"one spray boom deactivates mid-mission; flow rate halves; solenoid valve click audible but no flow change; boom isolation fault in app","root_cause":"T60 dual-pump system uses solenoid valves to isolate left/right booms; chemical residue crystallises on valve seat after missions without flush; valve actuator cannot overcome crystal buildup even with full solenoid force","severity":"high","mtbf_hours":100,"source_urls":["unverified-training-data"],"confidence":"low","tags":["spray-system","solenoid-valve","clogging","chemical"],"repair_protocol":{"title":"Boom Isolation Solenoid Valve Cleaning and Replacement","steps":[{"step":1,"action":"Power off; drain all spray lines; identify stuck solenoid valve from boom isolation fault code","tool":"DJI Agras app fault log"},{"step":2,"action":"Disconnect valve electrical connector; remove solenoid valve body (2x M4 screws, quick-disconnect fittings)","tool":"3mm hex wrench, fitting release tool"},{"step":3,"action":"Soak valve in warm water with 5% citric acid for 30 minutes; actuate manually 20x during soak","tool":"citric acid solution, container"},{"step":4,"action":"Rinse with clean water; test electrical actuation with 12V bench supply \u2014 valve must fully open in < 100ms","tool":"12V bench power supply, timer"},{"step":5,"action":"If valve does not actuate freely after cleaning, replace valve; reinstall with fresh thread seal tape on fittings","tool":"PTFE thread tape, 3mm hex wrench"},{"step":6,"action":"Power on; run boom isolation test in DJI Agras app; verify both booms activate and isolate correctly","tool":"DJI Agras app"}],"tools_required":["3mm hex wrench","fitting release tool","citric acid","container","12V bench power supply","PTFE thread tape","DJI Agras app"],"parts":[{"part_name":"DJI Agras T60 Boom Isolation Solenoid Valve","part_number":"CP.AG.00000512.01","supplier":"DJI Official Store","unit_cost_usd":55,"qty":1}],"labor_minutes":50,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"boom_flow_asymmetry_pct","signal_source":"dual flow sensor telemetry","threshold_value":15,"threshold_operator":">","threshold_unit":"percent left vs right","lead_time_hours":2,"confidence":0.82}]},{"component":"50L folding tank baffle \u2014 slosh-induced structural fatigue","symptom":"asymmetric yaw during fast direction reversals with partially filled tank; tank audible sloshing during mission; cracked baffle visible on tank inspection","root_cause":"T60's 50L tank contains internal baffles to reduce liquid slosh; repeated high-acceleration direction changes at partial fill (25-35L) create hydraulic impact loads on baffle welds exceeding fatigue limit after 500+ full missions","severity":"medium","mtbf_hours":500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["tank","structural","slosh","fatigue","flight-dynamics"],"repair_protocol":{"title":"Tank Baffle Inspection and Tank Module Replacement","steps":[{"step":1,"action":"Power off; drain tank completely; remove tank from aircraft (6x M5 quick-release fasteners)","tool":"M5 quick-release key"},{"step":2,"action":"Use inspection camera to view tank interior through fill port; inspect all baffle attachment points for cracks","tool":"endoscope/borescope camera, phone flashlight"},{"step":3,"action":"If baffle cracked at weld: condemn tank module \u2014 field repair of HDPE tank not possible; install new tank module","tool":null},{"step":4,"action":"Install new tank; secure all 6 fasteners; reconnect tank level sensor and drain valve","tool":"M5 quick-release key, spudger"},{"step":5,"action":"Fill to 25L with clean water; perform direction reversal hover test; verify IMU yaw does not deviate > 3 degrees during reversal","tool":"DJI Agras app, remote control"}],"tools_required":["M5 quick-release key","endoscope camera","spudger","DJI Agras app"],"parts":[{"part_name":"DJI Agras T60 50L Tank Module","part_number":"CP.AG.00000498.01","supplier":"DJI Official Store","unit_cost_usd":320,"qty":1}],"labor_minutes":30,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"yaw_oscillation_amplitude_deg","signal_source":"IMU flight controller","threshold_value":4,"threshold_operator":">","threshold_unit":"degrees peak-to-peak","lead_time_hours":2,"confidence":0.7}]},{"component":"ESC gate driver IC \u2014 failure from voltage spike","symptom":"specific motor drops to 0 RPM mid-flight; ESC error code motor_fault; remaining motors compensate; aircraft descends to emergency landing","root_cause":"T60 heavy payload requires high motor current; inductive voltage spikes during rapid throttle changes can exceed gate driver IC breakdown voltage; gate driver ICs in outer arm ESCs experience higher EMI exposure","severity":"critical","mtbf_hours":800,"source_urls":["unverified-training-data"],"confidence":"low","tags":["ESC","gate-driver","electrical","critical","motor-failure"],"repair_protocol":{"title":"Failed ESC Module Replacement","steps":[{"step":1,"action":"Power off; identify failed ESC from flight log motor fault codes","tool":"DJI Agras app flight records"},{"step":2,"action":"Remove propeller from affected motor; remove ESC cover (2x M3 screws)","tool":"DJI prop wrench, JIS #1 screwdriver"},{"step":3,"action":"Remove failed ESC (4x M3 mounting screws); disconnect phase wires, power leads, and CAN connector","tool":"JIS #1 screwdriver, label tape"},{"step":4,"action":"Install new ESC module; reconnect phase wires in correct order (label tape reference); reconnect power and CAN","tool":"JIS #1 screwdriver"},{"step":5,"action":"Reinstall ESC cover and propeller; power on; run ESC calibration in DJI Agras app","tool":"DJI Agras app"},{"step":6,"action":"Perform tethered hover test for 5 minutes; verify all 8 motor currents within 10% of each other","tool":"safety tether system, DJI Agras app"}],"tools_required":["DJI prop wrench","JIS #1 screwdriver","label tape","DJI Agras app","safety tether system"],"parts":[{"part_name":"DJI Agras T60 ESC Module","part_number":"CP.AG.00000505.01","supplier":"DJI Official Store","unit_cost_usd":310,"qty":1}],"labor_minutes":35,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"motor_rpm_deviation_pct","signal_source":"ESC telemetry","threshold_value":8,"threshold_operator":">","threshold_unit":"percent from commanded","lead_time_hours":2,"confidence":0.8},{"signal_name":"esc_voltage_spike_event_count","signal_source":"ESC protection log","threshold_value":5,"threshold_operator":">","threshold_unit":"spike events per flight","lead_time_hours":4,"confidence":0.72}]},{"component":"boom hinge pin \u2014 corrosion seizure","symptom":"spray boom will not fold/unfold; hinge pivot galled; boom folds with abnormal force; hinge shows visible rust or galvanic corrosion","root_cause":"T60 folding boom hinges are steel pins in aluminium housings; agricultural chemical atmosphere is corrosive; galvanic corrosion at steel/aluminium interface causes hinge seizure when anti-corrosion grease interval is missed","severity":"medium","mtbf_hours":300,"source_urls":["unverified-training-data"],"confidence":"low","tags":["boom","hinge","corrosion","mechanical","structural"],"repair_protocol":{"title":"Boom Hinge Pin Lubrication and Replacement","steps":[{"step":1,"action":"Inspect all boom hinges for corrosion and smooth operation before each weekly maintenance","tool":"flashlight, nitrile gloves"},{"step":2,"action":"Apply Corrosion-X to hinge pin; work boom through full fold/unfold cycle 10x to distribute lubricant","tool":"Corrosion-X spray"},{"step":3,"action":"If hinge still stiff or galled: press out hinge pin using 3mm punch and hammer","tool":"3mm pin punch, small hammer"},{"step":4,"action":"Clean hinge bore with spiral brush; coat with Molykote BR-2 grease; install new stainless steel hinge pin","tool":"spiral bore brush, Molykote BR-2, bench press or drift"},{"step":5,"action":"Verify boom folds/unfolds with < 5N force; install retention clip","tool":"spring scale 0-20N, snap ring pliers"}],"tools_required":["Corrosion-X spray","3mm pin punch","small hammer","spiral bore brush","Molykote BR-2 grease","snap ring pliers","spring scale"],"parts":[{"part_name":"DJI Agras T60 Boom Hinge Pin (2x stainless)","part_number":"CP.AG.00000519.01","supplier":"DJI Official Store","unit_cost_usd":22,"qty":1}],"labor_minutes":30,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"boom_fold_force_n","signal_source":"manual inspection log","threshold_value":8,"threshold_operator":">","threshold_unit":"newtons to initiate fold","lead_time_hours":48,"confidence":0.75}]},{"component":"TB60 battery \u2014 accelerated aging from partial-state charging","symptom":"usable flight time drops below 8 minutes at 60kg payload; app reports cell capacity < 78%; battery swells visibly","root_cause":"T60 multi-battery swap operations leave batteries in partial state of charge for hours in hot conditions; repeated partial charge-discharge cycles at high temperature accelerate NMC cell aging through lithium plating at anode","severity":"high","mtbf_hours":500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["battery","TB60","NMC","thermal","aging"],"repair_protocol":{"title":"TB60 Battery Reconditioning and Retirement Assessment","steps":[{"step":1,"action":"Check TB60 battery app report: if remaining capacity < 80% or swelling visible, retire immediately","tool":"DJI Agras app, visual inspection"},{"step":2,"action":"For batteries 80-90% remaining: perform DJI battery station reconditioning cycle (discharge to storage, full charge, discharge to storage)","tool":"DJI battery charging station"},{"step":3,"action":"Measure post-reconditioning capacity \u2014 if < 85% of rated, retire","tool":"DJI Agras app battery details"},{"step":4,"action":"During field operations: avoid storing charged TB60 in direct sun; use insulated battery cases between uses","tool":"insulated battery carrying case"}],"tools_required":["DJI Agras app","DJI battery charging station","insulated battery carrying case"],"parts":[{"part_name":"DJI Agras T60 TB60 Intelligent Flight Battery","part_number":"CP.AG.00000489.01","supplier":"DJI Official Store","unit_cost_usd":580,"qty":1}],"labor_minutes":15,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"battery_capacity_remaining_pct","signal_source":"DJI BMS app","threshold_value":82,"threshold_operator":"<","threshold_unit":"percent","lead_time_hours":24,"confidence":0.85}]},{"component":"RTK antenna \u2014 corrosion from chemical spray overspray","symptom":"RTK positioning accuracy degrades from 2cm to > 1m; aircraft position hold oscillates; GPS fallback mode triggered","root_cause":"RTK antenna on T60 is mounted above tank; spray mist reaches antenna in crosswind conditions; chemical film changes antenna dielectric environment and degrades SMA connector contacts; repeated chemical exposure eventually corrodes connector","severity":"medium","mtbf_hours":800,"source_urls":["unverified-training-data"],"confidence":"low","tags":["RTK","antenna","corrosion","GPS","chemical"],"repair_protocol":{"title":"RTK Antenna Cleaning and Connector Inspection","steps":[{"step":1,"action":"Power off; inspect RTK antenna patch and SMA connector for chemical residue or corrosion","tool":"magnifying glass, flashlight"},{"step":2,"action":"Clean antenna surface with water-dampened cloth; dry completely","tool":"damp cloth, dry cloth"},{"step":3,"action":"Apply DeoxIT D5 to SMA connector threads; mate and demate 5x; dry with compressed air","tool":"DeoxIT D5, compressed air"},{"step":4,"action":"Inspect SMA connector center pin for corrosion pitting \u2014 if visible green or black corrosion on pin face, replace antenna assembly","tool":"magnifying glass"},{"step":5,"action":"Apply thin coat of Corrosion-X to SMA connector exterior after cleaning; do not get inside connector","tool":"Corrosion-X"},{"step":6,"action":"Power on; check RTK accuracy in open field \u2014 verify FIXED solution within 90 seconds and horizontal accuracy < 3cm","tool":"DJI Agras app RTK status"}],"tools_required":["magnifying glass","DeoxIT D5","Corrosion-X","compressed air","damp cloth","DJI Agras app"],"parts":[{"part_name":"DJI Agras T60 RTK Antenna Assembly","part_number":"CP.AG.00000523.01","supplier":"DJI Official Store","unit_cost_usd":75,"qty":1}],"labor_minutes":20,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"rtk_horizontal_accuracy_cm","signal_source":"DJI RTK module","threshold_value":5,"threshold_operator":">","threshold_unit":"centimeters","lead_time_hours":4,"confidence":0.78},{"signal_name":"rtk_fix_time_sec","signal_source":"DJI RTK status log","threshold_value":120,"threshold_operator":">","threshold_unit":"seconds to fixed","lead_time_hours":8,"confidence":0.72}]}],"suppliers":[{"name":"DJI Official Store","website":"https://store.dji.com","region":"CN","component_types":["all T60 parts","battery","ESC","motor","spray system"],"lead_time_days":7,"risk_level":"low"}],"research_sources":["unverified-training-data"]},{"slug":"dji-matrice-350","name":"DJI Matrice 350 RTK","manufacturer":"DJI","type":"drone","introduced_year":2023,"specs_json":{"weight_kg":6.47,"payload_kg":2.7,"battery":"TB65 hot-swap dual","max_speed_ms":23,"ip_rating":"IP55","endurance_min":55,"comms":"O3 Enterprise 20km","rtk":"true","lidar":"optional payload","camera_ports":3},"failure_modes":[{"component":"gimbal ribbon cable \u2014 ZIF connector fatigue","symptom":"gimbal image freezes intermittently; camera telemetry disappears from app; physical twisting of gimbal arm resolves temporarily","root_cause":"gimbal ribbon cable routes through pivot point and experiences repeated flex cycles; ZIF connector at drone body end develops fretting oxidation from micro-movement during vibration; ribbon cable outer insulation cracks at bend radius","severity":"high","mtbf_hours":1200,"source_urls":["unverified-training-data"],"confidence":"low","tags":["gimbal","cable","ZIF","intermittent","electrical"],"repair_protocol":{"title":"Gimbal Ribbon Cable Replacement","steps":[{"step":1,"action":"Power off; remove gimbal from aircraft (3x M2.5 screws at gimbal mount plate)","tool":"JIS #0 screwdriver"},{"step":2,"action":"Trace ribbon cable from gimbal body to ZIF connector at drone; carefully lift ZIF connector latch with spudger","tool":"spudger, tweezers"},{"step":3,"action":"Extract ribbon cable from ZIF slot; inspect for cracks along flex zone","tool":"magnifying glass"},{"step":4,"action":"Slide new ribbon cable into ZIF connector with contacts facing correct direction; press latch down until click","tool":"tweezers, spudger"},{"step":5,"action":"Route cable with same bend radius as original \u2014 must not be kinked or pinched by gimbal housing","tool":null},{"step":6,"action":"Reinstall gimbal; power on; verify live video from all cameras; perform gimbal auto-calibration","tool":"DJI Pilot 2 app"}],"tools_required":["JIS #0 screwdriver","spudger","tweezers","magnifying glass","DJI Pilot 2 app"],"parts":[{"part_name":"DJI M350 RTK Gimbal Ribbon Cable","part_number":"CP.EN.00000395.01","supplier":"DJI Enterprise Store","unit_cost_usd":45,"qty":1}],"labor_minutes":40,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"camera_signal_dropout_per_hour","signal_source":"DJI transmission link statistics","threshold_value":3,"threshold_operator":">","threshold_unit":"dropouts per flight hour","lead_time_hours":8,"confidence":0.75}]},{"component":"TB65 battery pair \u2014 cell capacity mismatch between paired units","symptom":"one battery discharges faster than partner; aircraft lands with asymmetric battery SOC (difference > 15%); system logs dual-battery balance warning","root_cause":"M350 hot-swap system pairs two TB65 batteries; aging batteries develop differing internal resistance; high-current equalization between mismatched cells stresses the weaker battery and reduces overall capacity","severity":"medium","mtbf_hours":1000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["battery","TB65","pairing","dual-battery","balance"],"repair_protocol":{"title":"TB65 Battery Pair Evaluation and Matched Replacement","steps":[{"step":1,"action":"Check both TB65 SOH via DJI app; batteries with > 5% SOH difference should not be paired","tool":"DJI Pilot 2 app"},{"step":2,"action":"Perform DJI battery station full discharge-charge cycle on each battery individually; record final capacity","tool":"DJI battery charging station"},{"step":3,"action":"Pair two batteries with capacity within 3% of each other; label pairs with matching tape color","tool":"colored label tape"},{"step":4,"action":"Retire any battery with SOH < 80%","tool":null}],"tools_required":["DJI Pilot 2 app","DJI battery charging station","colored label tape"],"parts":[{"part_name":"DJI M350 TB65 Intelligent Flight Battery","part_number":"CP.EN.00000353.01","supplier":"DJI Enterprise Store","unit_cost_usd":580,"qty":1}],"labor_minutes":20,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"dual_battery_soc_delta_pct","signal_source":"BMS dual-battery management","threshold_value":10,"threshold_operator":">","threshold_unit":"percent SOC difference","lead_time_hours":4,"confidence":0.82}]},{"component":"IP55 ingress protection \u2014 gasket degradation","symptom":"moisture alarm after rain flight; connector pins show corrosion after wet operations; internal humidity sensor > 70%","root_cause":"M350 IP55 protection depends on perimeter gasket and sealed connector boots; repeated battery removal/replacement cycles flex body panels and compress gaskets permanently; field cleaning with pressure washers accelerates gasket degradation","severity":"high","mtbf_hours":2000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["sealing","IP55","gasket","water-ingress","maintenance"],"repair_protocol":{"title":"M350 Body Gasket Inspection and Replacement","steps":[{"step":1,"action":"Power off; remove all payloads and batteries; open body panels per DJI M350 service guide (T10 Torx)","tool":"T10 Torx driver"},{"step":2,"action":"Inspect all perimeter gaskets; look for compression set (< 50% original thickness) or tears","tool":"vernier calipers, magnifying glass"},{"step":3,"action":"Remove degraded gaskets; clean groove with IPA; install new OEM gasket set","tool":"IPA, lint-free cloth, plastic scraper"},{"step":4,"action":"Ensure all connector rubber boots are fully seated; replace any cracked boots","tool":null},{"step":5,"action":"Reassemble body panels; torque T10 screws to 1.5 Nm; perform IP55 water spray test 3 minutes at 12.5L/min","tool":"torque wrench, garden hose adjustable nozzle"},{"step":6,"action":"Monitor internal humidity via app 30 minutes after spray test \u2014 must remain < 60% RH","tool":"DJI Pilot 2 app humidity monitor"}],"tools_required":["T10 Torx","torque wrench","IPA","vernier calipers","lint-free cloth","garden hose","DJI Pilot 2 app"],"parts":[{"part_name":"DJI M350 RTK Body Gasket Set","part_number":"CP.EN.00000388.01","supplier":"DJI Enterprise Store","unit_cost_usd":38,"qty":1}],"labor_minutes":60,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"internal_humidity_rh_pct","signal_source":"M350 internal humidity sensor","threshold_value":65,"threshold_operator":">","threshold_unit":"percent RH","lead_time_hours":8,"confidence":0.82}]},{"component":"O3 Enterprise antenna cable \u2014 vibration fatigue at connector","symptom":"transmission range drops from 20km to < 5km; video latency spikes; connection drops during bank manoeuvres","root_cause":"O3 Enterprise antenna cables route through airframe from antenna array to main board; vibration at motor mount frequencies creates resonant stress at SMA connector crimp; repeated flex causes partial centre conductor fracture","severity":"medium","mtbf_hours":1500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["communications","antenna","cable","O3","vibration"],"repair_protocol":{"title":"O3 Antenna Cable Inspection and Replacement","steps":[{"step":1,"action":"Identify failed antenna direction via DJI RCF signal quality display \u2014 weakest direction indicates failed antenna","tool":"DJI RC Plus or DJI Pilot 2 app"},{"step":2,"action":"Power off; remove airframe access panel for antenna routing area","tool":"T10 Torx"},{"step":3,"action":"Gently flex antenna cable near SMA connector while monitoring cable continuity with DMM \u2014 opens indicate fracture location","tool":"digital multimeter, spudger"},{"step":4,"action":"Disconnect SMA connector; route new OEM cable following original path; reconnect SMA both ends finger-tight + 1/4 turn","tool":"SMA torque wrench (0.56 Nm)","warning":"Never overtighten SMA \u2014 0.56 Nm maximum; overtorque cracks centre pin"},{"step":5,"action":"Reassemble access panel; perform range test at 2km distance; verify RSSI > -85dBm","tool":"DJI Pilot 2 app, open flight area"}],"tools_required":["T10 Torx","digital multimeter","SMA torque wrench 0.56 Nm","spudger","DJI Pilot 2 app"],"parts":[{"part_name":"DJI M350 O3 Enterprise Antenna Cable Set","part_number":"CP.EN.00000401.01","supplier":"DJI Enterprise Store","unit_cost_usd":55,"qty":1}],"labor_minutes":45,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"o3_rssi_dbm_min","signal_source":"DJI link telemetry","threshold_value":-88,"threshold_operator":"<","threshold_unit":"dBm","lead_time_hours":4,"confidence":0.75}]},{"component":"landing gear strut \u2014 damper elastomer fatigue","symptom":"hard landings despite slow descent; landing vibration spike > 5g on IMU at touchdown; aircraft bounces on landing; damper visually compressed or cracked","root_cause":"M350 landing gear uses elastomer vibration dampers; repeated hard landings or landing on uneven terrain compress dampers beyond design limits; UV and ozone exposure accelerates elastomer oxidation and cracking","severity":"medium","mtbf_hours":1500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["landing-gear","damper","wear","structural"],"repair_protocol":{"title":"Landing Gear Damper Replacement","steps":[{"step":1,"action":"Inspect all 4 landing gear dampers; press each with thumb \u2014 damper should spring back; cracked or permanently compressed: replace","tool":"flashlight"},{"step":2,"action":"Remove landing gear strut from body (2x M3 screws per strut); extract damper insert from strut tip","tool":"2.5mm hex wrench, circlip pliers"},{"step":3,"action":"Press new damper insert into strut tip until seated; reinstall strut; torque M3 screws to 1.5 Nm","tool":"2.5mm hex wrench, torque wrench 0-3 Nm"},{"step":4,"action":"Perform 5 practice landings on flat surface; verify IMU touchdown vibration < 3g","tool":"DJI Pilot 2 app flight data"}],"tools_required":["2.5mm hex wrench","circlip pliers","torque wrench 0-3 Nm","DJI Pilot 2 app"],"parts":[{"part_name":"DJI M350 RTK Landing Gear Damper Set (4x)","part_number":"CP.EN.00000375.01","supplier":"DJI Enterprise Store","unit_cost_usd":32,"qty":1}],"labor_minutes":20,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"landing_vibration_peak_g","signal_source":"IMU flight log at touchdown event","threshold_value":4.5,"threshold_operator":">","threshold_unit":"g","lead_time_hours":4,"confidence":0.8}]},{"component":"RTK antenna \u2014 ground plane corrosion","symptom":"RTK fix takes > 3 minutes; horizontal accuracy degrades to > 10cm in good GNSS conditions; position hold oscillates","root_cause":"M350 RTK antenna ground plane is aluminium; field exposure to rain, dew, and cleaning agents causes surface oxidation; oxidised ground plane reduces antenna radiation efficiency and multi-path rejection","severity":"medium","mtbf_hours":2500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["RTK","antenna","corrosion","GPS","positioning"],"repair_protocol":{"title":"RTK Antenna Ground Plane Cleaning and Inspection","steps":[{"step":1,"action":"Power off; inspect RTK antenna and ground plane for oxidation (white powder on aluminium)","tool":"flashlight, magnifying glass"},{"step":2,"action":"Clean ground plane with aluminium-safe contact cleaner; remove white oxide deposits","tool":"DeoxIT D5, soft toothbrush"},{"step":3,"action":"Apply thin coat of ACF-50 anti-corrosion film to ground plane; allow 5 minutes to dry","tool":"ACF-50 anti-corrosion compound"},{"step":4,"action":"Check SMA connector on RTK module for corrosion; treat with DeoxIT if needed","tool":"DeoxIT D5"},{"step":5,"action":"Power on in open sky; verify RTK FIXED solution < 90 seconds and accuracy < 3cm CEP","tool":"DJI Pilot 2 app RTK status"}],"tools_required":["DeoxIT D5","soft toothbrush","ACF-50 anti-corrosion compound","DJI Pilot 2 app"],"parts":[{"part_name":"DJI M350 RTK Antenna Assembly (if ground plane damaged)","part_number":"CP.EN.00000408.01","supplier":"DJI Enterprise Store","unit_cost_usd":95,"qty":1}],"labor_minutes":20,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"rtk_fix_time_sec","signal_source":"DJI RTK status","threshold_value":120,"threshold_operator":">","threshold_unit":"seconds to FIXED","lead_time_hours":8,"confidence":0.75}]}],"suppliers":[{"name":"DJI Enterprise Store","website":"https://enterprise.dji.com","region":"CN","component_types":["all M350 parts","battery","gimbal cable","antenna","gasket"],"lead_time_days":5,"risk_level":"low"}],"research_sources":["unverified-training-data"]}]$jdata$::jsonb;
  p   jsonb;
  fm  jsonb;
  sig jsonb;
  pid  uuid;
  fmid uuid;
BEGIN
  FOR p IN SELECT value FROM jsonb_array_elements(d)
  LOOP
    SELECT id INTO pid FROM platforms WHERE slug = p->>'slug';
    IF pid IS NULL THEN
      INSERT INTO platforms (slug,name,manufacturer,type,introduced_year,specs_json,techmedix_status)
      VALUES (p->>'slug',p->>'name',p->>'manufacturer',p->>'type',
              NULLIF(p->>'introduced_year','null')::integer,
              COALESCE(p->'specs_json','{}'::jsonb),'supported')
      RETURNING id INTO pid;
    END IF;
    FOR fm IN SELECT value FROM jsonb_array_elements(p->'failure_modes')
    LOOP
      INSERT INTO failure_modes (platform_id,component,symptom,root_cause,severity,mtbf_hours,source_urls,confidence,tags)
      VALUES (pid, fm->>'component', fm->>'symptom', fm->>'root_cause',
              COALESCE(fm->>'severity','medium'),
              NULLIF(fm->>'mtbf_hours','null')::integer,
              ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'source_urls','["unverified-training-data"]'::jsonb))),
              COALESCE(fm->>'confidence','low'),
              ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'tags','[]'::jsonb))))
      ON CONFLICT (platform_id,component,symptom) DO UPDATE SET severity=EXCLUDED.severity, updated_at=now()
      RETURNING id INTO fmid;
      IF fm ? 'repair_protocol' THEN
        INSERT INTO repair_protocols (failure_mode_id,title,steps_json,tools_required,parts_json,labor_minutes,skill_level,source_url,verified_by,version)
        SELECT fmid,
               fm->'repair_protocol'->>'title',
               COALESCE(fm->'repair_protocol'->'steps','[]'::jsonb),
               ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'repair_protocol'->'tools_required','[]'::jsonb))),
               COALESCE(fm->'repair_protocol'->'parts','[]'::jsonb),
               NULLIF(fm->'repair_protocol'->>'labor_minutes','null')::integer,
               COALESCE(fm->'repair_protocol'->>'skill_level','intermediate'),
               fm->'repair_protocol'->>'source_url',
               'research_agent', 1
        WHERE NOT EXISTS (SELECT 1 FROM repair_protocols WHERE failure_mode_id=fmid);
      END IF;
      FOR sig IN SELECT value FROM jsonb_array_elements(COALESCE(fm->'predictive_signals','[]'::jsonb))
      LOOP
        INSERT INTO predictive_signals (failure_mode_id,signal_name,signal_source,threshold_value,threshold_operator,threshold_unit,lead_time_hours,confidence,notes)
        SELECT fmid, sig->>'signal_name', sig->>'signal_source',
               NULLIF(sig->>'threshold_value','null')::numeric,
               COALESCE(sig->>'threshold_operator','>'),
               sig->>'threshold_unit',
               NULLIF(sig->>'lead_time_hours','null')::integer,
               NULLIF(sig->>'confidence','null')::numeric,
               sig->>'notes'
        WHERE NOT EXISTS (SELECT 1 FROM predictive_signals WHERE failure_mode_id=fmid AND signal_name=sig->>'signal_name');
      END LOOP;
    END LOOP;
  END LOOP;
END $$;